`,paraId:63,tocIndex:11},{value:"\u5728 Next.js ",paraId:64,tocIndex:12},{value:"app/",paraId:64,tocIndex:12},{value:" \u76EE\u5F55\u4E2D\u7684\u9875\u9762\u9ED8\u8BA4\u662F",paraId:64,tocIndex:12},{value:"\u670D\u52A1\u5668\u7EC4\u4EF6",paraId:64,tocIndex:12},{value:"\uFF1A",paraId:64,tocIndex:12},{value:`// app/page.tsx - \u670D\u52A1\u5668\u7EC4\u4EF6
import { getCatNames } from '../lib/catNames';
import { RevealButton } from '../components/RevealButton';

export const dynamic = 'force-dynamic'; // \u793A\u4F8B\uFF1A\u786E\u4FDD\u6BCF\u6B21\u8BF7\u6C42\u90FD\u4F1A\u8FD0\u884C\uFF08\u53EF\u6309\u9700\u914D\u7F6E\uFF09

export default async function Page() {
  const names = await getCatNames(); // \u53EA\u5728\u670D\u52A1\u5668\u8FD0\u884C

  return (
    <main>
      <h1>Cat Name Reveal</h1>
      <RevealButton names={names} />
    </main>
  );
}
`,paraId:65,tocIndex:12},{value:"\u8FD9\u91CC\u53D1\u751F\u4E86\u51E0\u4EF6\u91CD\u8981\u7684\u4E8B\uFF1A",paraId:66,tocIndex:12},{value:"Page",paraId:67,tocIndex:12},{value:" \u662F\u670D\u52A1\u5668\u7EC4\u4EF6\uFF0C\u53EA\u5728\u670D\u52A1\u5668\u4E0A\u8FD0\u884C\uFF1B",paraId:67,tocIndex:12},{value:"\u5B83\u53EF\u4EE5 ",paraId:67,tocIndex:12},{value:"await getCatNames()",paraId:67,tocIndex:12},{value:"\uFF0C\u76F4\u63A5\u8BBF\u95EE\u670D\u52A1\u5668\u80FD\u529B\uFF1B",paraId:67,tocIndex:12},{value:"\u5B83\u628A ",paraId:67,tocIndex:12},{value:"names",paraId:67,tocIndex:12},{value:" \u4F5C\u4E3A props \u4F20\u7ED9 ",paraId:67,tocIndex:12},{value:"RevealButton",paraId:67,tocIndex:12},{value:"\uFF1B",paraId:67,tocIndex:12},{value:"names",paraId:67,tocIndex:12},{value:" \u901A\u8FC7 RSC \u7684\u4F20\u8F93\u534F\u8BAE\u88AB\u5E8F\u5217\u5316\u540E\u9001\u5F80\u5BA2\u6237\u7AEF\u3002",paraId:67,tocIndex:12},{value:"RevealButton",paraId:68,tocIndex:13},{value:" \u662F\u4E00\u4E2A\u5BA2\u6237\u7AEF\u7EC4\u4EF6\uFF0C\u9700\u8981\u7528 ",paraId:68,tocIndex:13},{value:"'use client'",paraId:68,tocIndex:13},{value:" \u663E\u5F0F\u6807\u8BB0\uFF1A",paraId:68,tocIndex:13},{value:`// components/RevealButton.tsx - \u5BA2\u6237\u7AEF\u7EC4\u4EF6
'use client';

import { useState } from 'react';

type Props = {
  names: string[];
};

export function RevealButton({ names }: Props) {
  const [name, setName] = useState<string | null>(null);

  function handleClick() {
    const index = Math.floor(Math.random() * names.length);
    setName(names[index]);
  }

  return (
    <div>
      <button onClick={handleClick}>Reveal</button>
      {name && <p>Cat name: {name}</p>}
    </div>
  );
}
