function pauseableAdd(a, b, k) {
  // \u51BB\u7ED3\u672A\u6765\uFF1A\u4E0D\u7ACB\u5373\u6267\u884C k\uFF0C\u800C\u662F\u5B58\u8D77\u6765
  savedContinuation = () => k(a + b);
}

// \u89E6\u53D1\u8BA1\u7B97
pauseableAdd(1, 2, (res) => console.log('\u7ED3\u679C:', res));

console.log('\u8BA1\u7B97\u6682\u505C\u4E2D...');

// ... \u6A21\u62DF\uFF1A\u8FC7\u4E86\u4E00\u4F1A\u513F\uFF0C\u7528\u6237\u70B9\u51FB\u4E86\u201C\u7EE7\u7EED\u201D\u6309\u94AE
setTimeout(() => {
  if (savedContinuation) {
    console.log('\u6062\u590D\u6267\u884C');
    savedContinuation();
  }
}, 1000);
`,paraId:18,tocIndex:8},{value:"\u{1F525} \u4E1A\u754C\u5E94\u7528\uFF1AReact Fiber",paraId:19,tocIndex:8},{value:`
