import clsx, { ClassValue } from 'clsx';

// \u521B\u5EFA\u4E00\u4E2A\u901A\u7528\u7684 cn \u8F85\u52A9\u51FD\u6570
export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

// \u5728\u7EC4\u4EF6\u4E2D\u4F7F\u7528
<button
  className={cn(
    'base-class',
    {
      'variant-class': condition,
    },
    props.className,
  )}
/>;
