`,paraId:26,tocIndex:11},{value:`// 1. \u5904\u7406\u5927\u6574\u6570 ID
const userId = 9223372036854775807n;

// 2. \u9AD8\u7CBE\u5EA6\u65F6\u95F4\u6233\uFF08\u7EB3\u79D2\uFF09
const timestamp = BigInt(Date.now()) * 1000000n;

// 3. \u5927\u6570\u9636\u4E58\u8BA1\u7B97
function factorial(n) {
  let result = 1n;
  for (let i = 2n; i <= n; i++) {
    result *= i;
  }
  return result;
}
console.log(factorial(20n)); // 2432902008176640000n

