`,paraId:9,tocIndex:4},{value:"\u53EA\u8981\u6570\u636E\u7ED3\u6784\u5177\u6709 Iterator \u63A5\u53E3\uFF0C\u90FD\u53EF\u4EE5\u4F7F\u7528\u6570\u7EC4\u5F62\u5F0F\u7684\u89E3\u6784\u8D4B\u503C\uFF1A",paraId:10,tocIndex:5},{value:`// Set \u89E3\u6784
let [x, y, z] = new Set(['a', 'b', 'c']);
console.log(x, y, z); // 'a' 'b' 'c'

// Map \u89E3\u6784
let [[key1, val1], [key2, val2]] = new Map([
  [1, 2],
  [3, 4],
]);
console.log(key1, val1, key2, val2); // 1 2 3 4

// Generator \u51FD\u6570\u89E3\u6784
function* fibs() {
  let a = 0;
  let b = 1;
  while (true) {
    yield a;
    [a, b] = [b, a + b];
  }
}
let [first, second, third, fourth, fifth] = fibs();
console.log(first, second, third, fourth, fifth); // 0 1 1 2 3
`,paraId:11,tocIndex:5},{value:"\u89E3\u6784\u8D4B\u503C\u5141\u8BB8\u6307\u5B9A\u9ED8\u8BA4\u503C\uFF0C\u53EA\u6709\u5F53\u5BF9\u5E94\u4F4D\u7F6E\u7684\u503C\u4E25\u683C\u7B49\u4E8E ",paraId:12,tocIndex:6},{value:"undefined",paraId:12,tocIndex:6},{value:" \u65F6\uFF0C\u9ED8\u8BA4\u503C\u624D\u4F1A\u751F\u6548\uFF1A",paraId:12,tocIndex:6},{value:`// \u57FA\u672C\u9ED8\u8BA4\u503C
