JSON.stringify('abc'); // '"abc"' - \u5B57\u7B26\u4E32\u4F1A\u88AB\u53CC\u5F15\u53F7\u5305\u88F9
JSON.stringify(123); // '123' - \u6570\u5B57\u8F6C\u4E3A\u5B57\u7B26\u4E32
