`,paraId:34,tocIndex:11},{value:`// \u68C0\u6D4B undefined
function isUndefined(value) {
  return typeof value === 'undefined';
  // \u6216\u8005
  return value === void 0;
}

// \u540C\u65F6\u68C0\u6D4B null \u548C undefined\uFF08\u63A8\u8350\u7528\u4E8E\u5224\u7A7A\uFF09
function isNullish(value) {
  return value == null; // \u7B49\u4EF7\u4E8E value === null || value === undefined
}

// \u4F7F\u7528\u793A\u4F8B
const obj = { foo: undefined, bar: null, baz: 0 };

isNullish(obj.foo); // true
isNullish(obj.bar); // true
isNullish(obj.baz); // false
isNullish(obj.notExist); // true
`,paraId:35,tocIndex:12},{value:"\u5728\u73B0\u4EE3 JavaScript \u4EE3\u7801\u4E2D\uFF0C\u5E94\u8BE5\u63A8\u8350\u4F7F\u7528 undefined \u8FD8\u662F null\uFF1F",paraId:8},{value:"\u542C\u7956\u5E08\u7237\u7684",paraId:36,tocIndex:14},{value:"\u63A8\u8350\u4F7F\u7528 ",paraId:37,tocIndex:15},{value:"undefined",paraId:37,tocIndex:15},{value:' \u4F5C\u4E3A\u9ED8\u8BA4\u7684"\u7A7A\u503C"',paraId:37,tocIndex:15},{value:`// \u2705 \u63A8\u8350\uFF1A\u4F7F\u7528 undefined
