let wr = new WeakRef(target);

// \u6E05\u9664\u5F3A\u5F15\u7528
target = null;

// \u26A0\uFE0F \u6CE8\u610F\uFF1A\u5BF9\u8C61\u4E0D\u4F1A\u7ACB\u5373\u88AB\u56DE\u6536
// deref() \u53EF\u80FD\u4ECD\u7136\u8FD4\u56DE\u5BF9\u8C61\uFF0C\u4E5F\u53EF\u80FD\u8FD4\u56DE undefined
// \u8FD9\u53D6\u51B3\u4E8E\u5783\u573E\u56DE\u6536\u5668\u4F55\u65F6\u8FD0\u884C
const obj = wr.deref();
if (obj) {
  console.log('\u5BF9\u8C61\u4ECD\u7136\u5B58\u5728');
} else {
  console.log('\u5BF9\u8C61\u5DF2\u88AB\u56DE\u6536');
}
