obj3.b.c = 30; // \u4E0D\u5F71\u54CD obj1.b.c
`,paraId:91,tocIndex:37},{value:"\u6CE8\u610F\uFF1A",paraId:92,tocIndex:37},{value:"JSON.parse(JSON.stringify(...))",paraId:92,tocIndex:37},{value:" \u6709\u8BF8\u591A\u5C40\u9650\uFF0C\u4E0D\u9002\u5408\u51FD\u6570\u3001",paraId:92,tocIndex:37},{value:"Date",paraId:92,tocIndex:37},{value:"\u3001",paraId:92,tocIndex:37},{value:"Map",paraId:92,tocIndex:37},{value:"\u3001\u5FAA\u73AF\u5F15\u7528\u7B49\u590D\u6742\u5BF9\u8C61\uFF0C\u4EC5\u80FD\u7528\u4E8E\u7B80\u5355\u6570\u636E\u7ED3\u6784\u3002",paraId:92,tocIndex:37},{value:"JavaScript \u4E2D\u6240\u6709\u51FD\u6570\u53C2\u6570\u90FD\u662F\u201C\u6309\u503C\u4F20\u9012\u201D\u3002",paraId:93,tocIndex:38},{value:"\u5BF9\u4E8E\u57FA\u672C\u7C7B\u578B\uFF1A\u590D\u5236\u7684\u662F\u503C\u672C\u8EAB\u3002",paraId:94,tocIndex:38},{value:"\u5BF9\u4E8E\u5F15\u7528\u7C7B\u578B\uFF1A\u590D\u5236\u7684\u662F\u201C\u5F15\u7528\u8FD9\u4E2A\u6307\u9488\u201D\u7684\u503C\uFF08\u5373\u6307\u9488\u672C\u8EAB\uFF09\u3002",paraId:94,tocIndex:38},{value:`// \u57FA\u672C\u7C7B\u578B
function changeValue(num) {
  num = 100;
  return num;
}

let value = 1;
const result = changeValue(value);

console.log(value); // 1
console.log(result); // 100

// \u5F15\u7528\u7C7B\u578B
function changeObject(person) {
  person.name = 'chu'; // \u4FEE\u6539\u539F\u5BF9\u8C61
  person = { name: 'bar', age: 18 }; // \u6539\u53D8\u7684\u662F\u5F62\u53C2\u6307\u5411
  return person;
}

const p1 = { name: 'foo', age: 25 };
const p2 = changeObject(p1);

console.log(p1); // { name: 'chu', age: 25 }
